"use client";

// Classification: D — third-party package retained for parity (embla-carousel-react).
// Faithful port of shadcn carousel.tsx; lucide icons replaced with Tabler,
// cn replaced with cx from @/lib/cva, Button imported from @/components/ui/button.

import { IconArrowLeft, IconArrowRight } from "@tabler/icons-react";
import useEmblaCarousel, { type UseEmblaCarouselType } from "embla-carousel-react";
import * as React from "react";

import { Button } from "@/components/ui/button";
import { cx } from "@/lib/cva";

type CarouselApi = UseEmblaCarouselType[1];
type UseCarouselParameters = Parameters<typeof useEmblaCarousel>;
type CarouselOptions = UseCarouselParameters[0];
type CarouselPlugin = UseCarouselParameters[1];

type CarouselProps = {
    opts?: CarouselOptions;
    plugins?: CarouselPlugin;
    orientation?: "horizontal" | "vertical";
    setApi?: (api: CarouselApi) => void;
};

type CarouselContextProps = {
    carouselRef: ReturnType<typeof useEmblaCarousel>[0];
    api: ReturnType<typeof useEmblaCarousel>[1];
    scrollPrev: () => void;
    scrollNext: () => void;
    canScrollPrev: boolean;
    canScrollNext: boolean;
} & CarouselProps;

let CarouselContext = React.createContext<CarouselContextProps | null>(null);

function useCarousel() {
    let context = React.useContext(CarouselContext);

    if (!context) {
        throw new Error("useCarousel must be used within a <Carousel />");
    }

    return context;
}

function Carousel({
    orientation = "horizontal",
    opts,
    setApi,
    plugins,
    className,
    children,
    ...props
}: React.ComponentProps<"div"> & CarouselProps) {
    let [carouselRef, api] = useEmblaCarousel(
        {
            ...opts,
            axis: orientation === "horizontal" ? "x" : "y",
        },
        plugins,
    );
    let [canScrollPrev, setCanScrollPrev] = React.useState(false);
    let [canScrollNext, setCanScrollNext] = React.useState(false);

    let onSelect = React.useCallback((api: CarouselApi) => {
        if (!api) return;
        setCanScrollPrev(api.canScrollPrev());
        setCanScrollNext(api.canScrollNext());
    }, []);

    let scrollPrev = React.useCallback(() => {
        api?.scrollPrev();
    }, [api]);

    let scrollNext = React.useCallback(() => {
        api?.scrollNext();
    }, [api]);

    let handleKeyDown = React.useCallback(
        (event: React.KeyboardEvent<HTMLDivElement>) => {
            if (event.key === "ArrowLeft") {
                event.preventDefault();
                scrollPrev();
            } else if (event.key === "ArrowRight") {
                event.preventDefault();
                scrollNext();
            }
        },
        [scrollPrev, scrollNext],
    );

    React.useEffect(() => {
        if (!api || !setApi) return;
        setApi(api);
    }, [api, setApi]);

    React.useEffect(() => {
        if (!api) return;
        onSelect(api);
        api.on("reInit", onSelect);
        api.on("select", onSelect);

        return () => {
            api?.off("select", onSelect);
        };
    }, [api, onSelect]);

    return (
        <CarouselContext.Provider
            value={{
                carouselRef,
                api,
                opts,
                orientation: orientation || (opts?.axis === "y" ? "vertical" : "horizontal"),
                scrollPrev,
                scrollNext,
                canScrollPrev,
                canScrollNext,
            }}
        >
            <div
                aria-roledescription="carousel"
                className={cx("relative", className)}
                data-slot="carousel"
                onKeyDownCapture={handleKeyDown}
                role="region"
                {...props}
            >
                {children}
            </div>
        </CarouselContext.Provider>
    );
}

function CarouselContent({ className, ...props }: React.ComponentProps<"div">) {
    let { carouselRef, orientation } = useCarousel();

    return (
        <div className="overflow-hidden" data-slot="carousel-content" ref={carouselRef}>
            <div
                className={cx(
                    "flex",
                    orientation === "horizontal" ? "-ml-4" : "-mt-4 flex-col",
                    className,
                )}
                {...props}
            />
        </div>
    );
}

function CarouselItem({ className, ...props }: React.ComponentProps<"div">) {
    let { orientation } = useCarousel();

    return (
        <div
            aria-roledescription="slide"
            className={cx(
                "min-w-0 shrink-0 grow-0 basis-full",
                orientation === "horizontal" ? "pl-4" : "pt-4",
                className,
            )}
            data-slot="carousel-item"
            role="group"
            {...props}
        />
    );
}

function CarouselPrevious({
    className,
    variant = "outline",
    size = "icon",
    ...props
}: React.ComponentProps<typeof Button>) {
    let { orientation, scrollPrev, canScrollPrev } = useCarousel();

    return (
        <Button
            className={cx(
                "absolute size-8 rounded-full",
                orientation === "horizontal"
                    ? "top-1/2 -left-12 -translate-y-1/2"
                    : "-top-12 left-1/2 -translate-x-1/2 rotate-90",
                className,
            )}
            data-slot="carousel-previous"
            isDisabled={!canScrollPrev}
            onPress={scrollPrev}
            size={size}
            variant={variant}
            {...props}
        >
            <IconArrowLeft aria-hidden="true" />
            <span className="sr-only">Previous slide</span>
        </Button>
    );
}

function CarouselNext({
    className,
    variant = "outline",
    size = "icon",
    ...props
}: React.ComponentProps<typeof Button>) {
    let { orientation, scrollNext, canScrollNext } = useCarousel();

    return (
        <Button
            className={cx(
                "absolute size-8 rounded-full",
                orientation === "horizontal"
                    ? "top-1/2 -right-12 -translate-y-1/2"
                    : "-bottom-12 left-1/2 -translate-x-1/2 rotate-90",
                className,
            )}
            data-slot="carousel-next"
            isDisabled={!canScrollNext}
            onPress={scrollNext}
            size={size}
            variant={variant}
            {...props}
        >
            <IconArrowRight aria-hidden="true" />
            <span className="sr-only">Next slide</span>
        </Button>
    );
}

export {
    type CarouselApi,
    Carousel,
    CarouselContent,
    CarouselItem,
    CarouselPrevious,
    CarouselNext,
    useCarousel,
};
